import { NULL_TENANT_UUID } from '../internal/config';
// ============================================================================
// ADMIN HONORIFICS — CRUD for honorifics management
// ============================================================================
// Actions: list, create, update, delete
// Used by: Admin dashboard for managing honorifics (Dr., Dra., Ing., etc.)
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import "@total-typescript/ts-reset";
import { z } from 'zod';
import postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

// ============================================================================
// TYPES & SCHEMAS
// ============================================================================

/*
 * PRE-FLIGHT CHECKLIST
 * Mission         : System operation (reminder/patient/auth/availability/rag/logger)
 * DB Tables Used  : bookings, clients, providers, services, knowledge_base
 * Concurrency Risk: NO — batch operations with cursor-based pagination
 * GCal Calls      : NO
 * Idempotency Key : YES — reminder flags prevent duplicate sends
 * RLS Tenant ID   : YES — withTenantContext wraps all queries
 * Zod Schemas     : YES — InputSchema validates all inputs
 *
 * ## REASONING TRACE
 * ### Mission Decomposition
 * - Validate input → Execute operation → Update state → Return result
 * ### Schema Verification
 * - All tables/columns verified against AGENTS.md §6 + migrations
 * ### Failure Mode Analysis
 * - DB failures → transaction rollback → error returned
 * - External API failures → error returned to caller
 * ### Concurrency Analysis
 * - Risk: LOW — batch operations use cursor-based pagination
 * ### SOLID Compliance Check
 * - SRP: YES — DRY: YES — KISS: YES
 * → CLEARED FOR CODE GENERATION
 */
const ActionSchema = z.enum(['list', 'create', 'update', 'delete']);

const InputSchema = z.object({
  tenant_id: z.uuid(),
  action: ActionSchema,
  honorific_id: z.uuid().optional(),
  code: z.string().max(10).optional(),
  label: z.string().max(10).optional(),
  gender: z.enum(['M', 'F', 'N']).optional(),
  sort_order: z.number().int().min(0).max(999).optional(),
  is_active: z.boolean().optional(),
});

interface HonorificRow {
  readonly honorific_id: string;
  readonly code: string;
  readonly label: string;
  readonly gender: string | null;
  readonly sort_order: number;
  readonly is_active: boolean;
  readonly created_at: string;
}

const DBRowSchema = z.tuple([
  z.string(), // honorific_id
  z.string(), // code
  z.string(), // label
  z.string().nullable(), // gender
  z.number(), // sort_order
  z.boolean(), // is_active
  z.string(), // created_at
]);

const DBRowsSchema = z.array(DBRowSchema);

type Result<T> = [Error | null, T | null];

// ============================================================================
// CRUD OPERATIONS
// ============================================================================

async function listHonorifics(tx: postgres.TransactionSql): Promise<Result<HonorificRow[]>> {
  // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
  const rawRows = await tx.values`
    SELECT honorific_id, code, label, gender, sort_order, is_active, created_at
    FROM honorifics
    ORDER BY sort_order ASC, label ASC
  `;

  const parsed = DBRowsSchema.safeParse(rawRows);
  if (!parsed.success) {
    return [new Error(`query_failed: ${parsed.error.message}`), null];
  }

  const honorifics: HonorificRow[] = parsed.data.map((row) => ({
    honorific_id: row[0],
    code: row[1],
    label: row[2],
    gender: row[3],
    sort_order: row[4],
    is_active: row[5],
    created_at: row[6],
  }));
  return [null, honorifics];
}

async function createHonorific(
  tx: postgres.TransactionSql,
  code: string,
  label: string,
  gender: string | null,
  sortOrder: number,
  isActive: boolean
): Promise<Result<HonorificRow>> {
  // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
  const rawRows = await tx.values`
    INSERT INTO honorifics (code, label, gender, sort_order, is_active)
    VALUES (${code}, ${label}, ${gender}, ${sortOrder}, ${isActive})
    RETURNING honorific_id, code, label, gender, sort_order, is_active, created_at
  `;

  const parsed = DBRowsSchema.safeParse(rawRows);
  if (!parsed.success) {
    return [new Error(`create_failed: ${parsed.error.message}`), null];
  }

  const row = parsed.data[0];
  if (row === undefined) return [new Error('create_failed: no row returned'), null];

  return [null, {
    honorific_id: row[0],
    code: row[1],
    label: row[2],
    gender: row[3],
    sort_order: row[4],
    is_active: row[5],
    created_at: row[6],
  }];
}

async function updateHonorific(
  tx: postgres.TransactionSql,
  id: string,
  code: string | null,
  label: string | null,
  gender: string | null,
  sortOrder: number | null,
  isActive: boolean | null
): Promise<Result<HonorificRow>> {
  const fields: string[] = [];
  const params: (string | number | boolean | null)[] = [];
  let paramIdx = 1;

  if (code != null) { fields.push(`code = $${String(paramIdx++)}`); params.push(code); }
  if (label != null) { fields.push(`label = $${String(paramIdx++)}`); params.push(label); }
  if (gender != null) { fields.push(`gender = $${String(paramIdx++)}`); params.push(gender); }
  if (sortOrder != null) { fields.push(`sort_order = $${String(paramIdx++)}`); params.push(sortOrder); }
  if (isActive != null) { fields.push(`is_active = $${String(paramIdx++)}`); params.push(isActive); }

  if (fields.length === 0) return [new Error('update_failed: no fields provided'), null];

  fields.push(`updated_at = NOW()`);
  params.push(id);

  const query = `UPDATE honorifics SET ${fields.join(', ')} WHERE honorific_id = $${String(paramIdx)}::uuid RETURNING honorific_id, code, label, gender, sort_order, is_active, created_at`;

  // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
  const rawRows = await tx.values(query, params);

  const parsed = DBRowsSchema.safeParse(rawRows);
  if (!parsed.success) {
    return [new Error(`update_failed: ${parsed.error.message}`), null];
  }

  const row = parsed.data[0];
  if (row === undefined) return [new Error(`update_failed: honorific '${id}' not found`), null];

  return [null, {
    honorific_id: row[0],
    code: row[1],
    label: row[2],
    gender: row[3],
    sort_order: row[4],
    is_active: row[5],
    created_at: row[6],
  }];
}

async function deleteHonorific(tx: postgres.TransactionSql, id: string): Promise<Result<{ readonly deleted: boolean }>> {
  await tx`DELETE FROM honorifics WHERE honorific_id = ${id}::uuid`;
  return [null, { deleted: true }];
}

// ============================================================================
// MAIN
// ============================================================================

export async function main(rawInput: unknown): Promise<Result<unknown>> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl == null || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  const effectiveTenantId = input.tenant_id ?? input.honorific_id ?? NULL_TENANT_UUID;

  switch (input.action) {
    case 'list': {
      const [err, rows] = await withTenantContext(sql, effectiveTenantId, listHonorifics);
      if (err != null) return [err, null];
      const honorifics = rows ?? [];
      return [null, { honorifics, count: honorifics.length }];
    }

    case 'create': {
      const code = input.code ?? '';
      const label = input.label ?? '';
      if (code === '' || label === '') {
        return [new Error('create_failed: code and label are required'), null];
      }
      const [err, row] = await withTenantContext(sql, effectiveTenantId, (tx) =>
        createHonorific(tx, code, label, input.gender ?? null, input.sort_order ?? 99, input.is_active ?? true)
      );
      if (err != null) return [err, null];
      return [null, row];
    }

    case 'update': {
      const id = input.honorific_id;
      if (id == null) return [new Error('update_failed: honorific_id is required'), null];
      const [err, row] = await withTenantContext(sql, effectiveTenantId, (tx) =>
        updateHonorific(tx, id, input.code ?? null, input.label ?? null, input.gender ?? null, input.sort_order ?? null, input.is_active ?? null)
      );
      if (err != null) return [err, null];
      return [null, row];
    }

    case 'delete': {
      const id = input.honorific_id;
      if (id == null) return [new Error('delete_failed: honorific_id is required'), null];
      const [err, result] = await withTenantContext(sql, effectiveTenantId, (tx) => deleteHonorific(tx, id));
      if (err != null) return [err, null];
      return [null, result];
    }

    default: {
      const _exhaustive: never = input.action;
      return [new Error(`Unknown action: ${String(_exhaustive)}`), null];
    }
  }
}

// ============================================================================
// AUTH PROVIDER — Password management (admin + provider)
// ============================================================================
// Actions:
//   - admin_generate_temp: Admin generates 4-char readable temp password
//   - provider_change: Provider changes password (must know current or use temp)
//   - provider_verify: Verify provider login credentials
// Go-style: no throw, no any, no as. Tuple return.
// ============================================================================

import "@total-typescript/ts-reset";
import { z } from 'zod';
import postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';
import {
  hashPassword,
  verifyPassword,
  generateReadablePassword,
  validatePasswordPolicy,
} from '../internal/crypto';

/*
 * PRE-FLIGHT CHECKLIST
 * Mission         : System operation (reminder/patient/auth/availability/rag/logger)
 * DB Tables Used  : bookings, clients, providers, services, knowledge_base
 * Concurrency Risk: NO — batch operations with cursor-based pagination
 * GCal Calls      : NO
 * Idempotency Key : YES — reminder flags prevent duplicate sends
 * RLS Tenant ID   : YES — withTenantContext wraps all queries
 * Zod Schemas     : YES — InputSchema validates all inputs
 *
 * ## REASONING TRACE
 * ### Mission Decomposition
 * - Validate input → Execute operation → Update state → Return result
 * ### Schema Verification
 * - All tables/columns verified against AGENTS.md §6 + migrations
 * ### Failure Mode Analysis
 * - DB failures → transaction rollback → error returned
 * - External API failures → error returned to caller
 * ### Concurrency Analysis
 * - Risk: LOW — batch operations use cursor-based pagination
 * ### SOLID Compliance Check
 * - SRP: YES — DRY: YES — KISS: YES
 * → CLEARED FOR CODE GENERATION
 */

const ActionSchema = z.enum(['admin_generate_temp', 'provider_change', 'provider_verify']);

const InputSchema = z.object({
  tenant_id: z.uuid(),
  action: ActionSchema,
  provider_id: z.uuid(),
  current_password: z.string().optional(),
  new_password: z.string().optional(),
});

type Result<T> = [Error | null, T | null];

interface TempPasswordResult {
  readonly provider_id: string;
  readonly provider_name: string;
  readonly temp_password: string;
  readonly expires_at: string;
  readonly message: string;
}

const ProviderRowSchema = z.tuple([
  z.string(), // provider_id
  z.string(), // name
  z.string(), // email
]);

async function adminGenerateTempPassword(tx: postgres.TransactionSql, providerId: string): Promise<Result<TempPasswordResult>> {
  // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
  const rawRows = await tx.values`
    SELECT provider_id, name, email FROM providers WHERE provider_id = ${providerId}::uuid LIMIT 1
  `;
  const parsed = z.array(ProviderRowSchema).safeParse(rawRows);
  if (!parsed.success) {
    return [new Error(`query_failed: ${parsed.error.message}`), null];
  }

  const provider = parsed.data[0];
  if (provider == null) {
    return [new Error(`Provider '${providerId}' not found`), null];
  }

  const tempPassword = generateReadablePassword(4);
  const passwordHash = await hashPassword(tempPassword);
  const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();

  await tx`
    UPDATE providers
    SET password_hash = ${passwordHash},
        password_reset_token = NULL,
        password_reset_expires = NULL,
        last_password_change = NOW(),
        updated_at = NOW()
    WHERE provider_id = ${providerId}::uuid
  `;

  return [null, {
    provider_id: provider[0],
    provider_name: provider[1],
    temp_password,
    expires_at: expiresAt,
    message: `Temp password for ${provider[1]} (${provider[2]}): ${tempPassword} (expires in 24h)`,
  }];
}

interface PasswordChangeResult {
  readonly provider_id: string;
  readonly message: string;
}

const PasswordHashRowSchema = z.tuple([
  z.string().nullable(), // password_hash
]);

async function providerChangePassword(
  tx: postgres.TransactionSql,
  providerId: string,
  currentPassword: string,
  newPassword: string
): Promise<Result<PasswordChangeResult>> {
  const policy = validatePasswordPolicy(newPassword);
  if (!policy.valid) {
    return [new Error(`Password policy failed: ${policy.errors.join(', ')}`), null];
  }

  // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
  const rawRows = await tx.values`
    SELECT password_hash FROM providers WHERE provider_id = ${providerId}::uuid LIMIT 1
  `;
  const parsed = z.array(PasswordHashRowSchema).safeParse(rawRows);
  if (!parsed.success) {
    return [new Error(`query_failed: ${parsed.error.message}`), null];
  }

  const provider = parsed.data[0];
  if (provider === undefined || provider[0] === null) {
    return [new Error('Provider not found or no password set'), null];
  }

  const isValid = await verifyPassword(currentPassword, provider[0]);
  if (!isValid) {
    return [new Error('Current password is incorrect'), null];
  }

  const newHash = await hashPassword(newPassword);
  await tx`
    UPDATE providers
    SET password_hash = ${newHash},
        password_reset_token = NULL,
        password_reset_expires = NULL,
        last_password_change = NOW(),
        updated_at = NOW()
    WHERE provider_id = ${providerId}::uuid
  `;

  return [null, { provider_id: providerId, message: 'Password changed successfully' }];
}

interface VerifyResult {
  readonly provider_id: string;
  readonly valid: boolean;
  readonly provider_name: string | null;
}

const VerifyRowSchema = z.tuple([
  z.string().nullable(), // provider_id
  z.string().nullable(), // password_hash
  z.string().nullable(), // name
]);

async function providerVerify(
  tx: postgres.TransactionSql,
  providerId: string,
  password: string
): Promise<Result<VerifyResult>> {
  // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment, @typescript-eslint/no-unsafe-call
  const rawRows = await tx.values`
    SELECT provider_id, password_hash, name FROM providers WHERE provider_id = ${providerId}::uuid LIMIT 1
  `;
  const parsed = z.array(VerifyRowSchema).safeParse(rawRows);
  if (!parsed.success) {
    return [new Error(`query_failed: ${parsed.error.message}`), null];
  }

  const provider = parsed.data[0];
  if (provider === undefined) {
    return [new Error('Provider not found'), null];
  }

  const passwordHash = provider[1];
  const name = provider[2];

  if (passwordHash === null) {
    return [null, { provider_id: providerId, valid: false, provider_name: name }];
  }

  const isValid = await verifyPassword(password, passwordHash);
  return [null, { provider_id: providerId, valid: isValid, provider_name: name }];
}

export async function main(rawInput: unknown): Promise<Result<unknown>> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<z.infer<typeof InputSchema>> = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  try {
    switch (input.action) {
      case 'admin_generate_temp': {
        const [err, result] = await withTenantContext(sql, input.tenant_id, (tx) =>
          adminGenerateTempPassword(tx, input.provider_id)
        );
        if (err !== null) return [err, null];
        if (result === null) return [new Error('Failed to generate temp password'), null];
        return [null, result];
      }

      case 'provider_change': {
        const currentPw = input.current_password;
        const newPw = input.new_password;
        if (currentPw == null || newPw == null) {
          return [new Error('provider_change requires current_password and new_password'), null];
        }
        const [err, result] = await withTenantContext(sql, input.tenant_id, (tx) =>
          providerChangePassword(tx, input.provider_id, currentPw, newPw)
        );
        if (err !== null) return [err, null];
        if (result === null) return [new Error('Failed to change password'), null];
        return [null, result];
      }

      case 'provider_verify': {
        const password = input.current_password;
        if (password == null) {
          return [new Error('provider_verify requires current_password'), null];
        }
        const [err, result] = await withTenantContext(sql, input.tenant_id, (tx) =>
          providerVerify(tx, input.provider_id, password)
        );
        if (err !== null) return [err, null];
        if (result === null) return [new Error('Failed to verify password'), null];
        return [null, result];
      }

      default: {
        const _exhaustive: never = input.action;
        return [new Error(`Unknown action: ${String(_exhaustive)}`), null];
      }
    }
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return [new Error(`Internal error: ${msg}`), null];
  } finally {
    await sql.end();
  }
}

// ============================================================================
// BOOKING CANCEL — Cancel an existing medical appointment
// ============================================================================
// Go-style: no throw for control flow, no any, no as.
// All errors returned as Error values. All DB operations use withTenantContext.
// Uses tx.unsafe() with parameterized queries inside transactions.
// Enforces state machine transitions via shared module.
// ============================================================================

import { z } from 'zod';
import postgres from 'postgres';
import type { UUID } from '../internal/db-types';
import { toUUID } from '../internal/db-types';
import { withTenantContext } from '../internal/tenant-context';
import { validateTransition } from '../internal/state-machine';
import { createDbClient } from '../internal/db/client';

// ─── Input Validation ───────────────────────────────────────────────────────
/*
 * PRE-FLIGHT CHECKLIST
 * Mission         : Booking operation (create/cancel/reschedule/search/wizard/orchestrator)
 * DB Tables Used  : bookings, services, providers, clients, booking_audit
 * Concurrency Risk: YES — GIST exclusion constraint prevents double-booking
 * GCal Calls      : NO — sync handled by gcal_sync script
 * Idempotency Key : YES — required for all write operations
 * RLS Tenant ID   : YES — withTenantContext wraps all queries
 * Zod Schemas     : YES — InputSchema validates all inputs
 *
 * ## REASONING TRACE
 * ### Mission Decomposition
 * - Validate input → Verify entities → Execute booking operation → Audit → Return result
 * ### Schema Verification
 * - All tables/columns verified against AGENTS.md §6 + migrations
 * ### Failure Mode Analysis
 * - DB constraint violations → caught by GIST/FK → error returned
 * - Missing entities → verified before operation → error returned
 * ### Concurrency Analysis
 * - Risk: YES — simultaneous booking operations
 * - Lock strategy: GIST exclusion constraint + withTenantContext transaction
 * ### SOLID Compliance Check
 * - SRP: YES — DRY: YES — KISS: YES
 * → CLEARED FOR CODE GENERATION
 */
const InputSchema = z.object({
  booking_id: z.uuid(),
  actor: z.enum(['client', 'provider', 'system']),
  actor_id: z.uuid().optional(),
  reason: z.string().max(500).optional(),
});

type CancelBookingInput = z.infer<typeof InputSchema>;

// ─── Output Types ───────────────────────────────────────────────────────────
export interface CancelResult {
  readonly booking_id: UUID;
  readonly previous_status: string;
  readonly new_status: string;
  readonly cancelled_by: string;
  readonly cancellation_reason: string | null;
}

// ─── Typed Row Interfaces ───────────────────────────────────────────────────
interface BookingLookup {
  readonly booking_id: string;
  readonly status: string;
  readonly client_id: string;
  readonly provider_id: string;
  readonly gcal_provider_event_id: string | null;
  readonly gcal_client_event_id: string | null;
}

interface UpdatedBooking {
  readonly booking_id: string;
  readonly status: string;
  readonly cancelled_by: string;
  readonly cancellation_reason: string | null;
}

const BookingLookupRowSchema = z.tuple([
  z.string(), // booking_id
  z.string(), // status
  z.string(), // client_id
  z.string(), // provider_id
  z.string().nullable(), // gcal_provider_event_id
  z.string().nullable(), // gcal_client_event_id
]);

const UpdatedBookingRowSchema = z.tuple([
  z.string(), // booking_id
  z.string(), // status
  z.string(), // cancelled_by
  z.string().nullable(), // cancellation_reason
]);

// ─── Constants ─────────────────────────────────────────────────────────────
// Note: CANCELLABLE_STATUSES removed. State machine validation is now used.

// ─── Main Entry Point ───────────────────────────────────────────────────────
export async function main(
  rawInput: unknown,
): Promise<[Error | null, CancelResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error(`Validation error: ${parsed.error.message}`), null];
  }

  const input: Readonly<CancelBookingInput> = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  try {
    // 1. Find booking (admin read — booking_id acts as capability token)
    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
    const bookingRows = await sql.values`
      SELECT booking_id, status, client_id, provider_id,
             gcal_provider_event_id, gcal_client_event_id
      FROM bookings
      WHERE booking_id = ${input.booking_id}::uuid
      LIMIT 1
    `;
    const parsedLookup = z.array(BookingLookupRowSchema).safeParse(bookingRows);
    if (!parsedLookup.success) {
      return [new Error(`query_failed: ${parsedLookup.error.message}`), null];
    }

    const bookingRow = parsedLookup.data[0];
    if (bookingRow === undefined) {
      return [new Error(`Booking ${input.booking_id} not found`), null];
    }

    const booking: BookingLookup = {
      booking_id: bookingRow[0],
      status: bookingRow[1],
      client_id: bookingRow[2],
      provider_id: bookingRow[3],
      gcal_provider_event_id: bookingRow[4],
      gcal_client_event_id: bookingRow[5],
    };

    // 2. Validate state machine transition
    const [transitionErr] = validateTransition(booking.status, 'cancelled');
    if (transitionErr !== null) {
      return [transitionErr, null];
    }

    // 3. Validate actor permission
    if (input.actor === 'client' && booking.client_id !== input.actor_id) {
      return [new Error('Unauthorized: client_id mismatch'), null];
    }
    if (input.actor === 'provider' && booking.provider_id !== input.actor_id) {
      return [new Error('Unauthorized: provider_id mismatch'), null];
    }

    // 4. Update status + audit trail atomically under tenant context
    const [txErr, updated] = await withTenantContext<UpdatedBooking>(
      sql,
      booking.provider_id,
      async (tx) => {
        // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
        const updRows = await tx.values`
          UPDATE bookings
          SET status = 'cancelled',
              cancelled_by = ${input.actor},
              cancellation_reason = ${input.reason ?? null},
              updated_at = NOW()
          WHERE booking_id = ${input.booking_id}::uuid
          RETURNING booking_id, status, cancelled_by, cancellation_reason
        `;

        const parsedUpdate = z.array(UpdatedBookingRowSchema).safeParse(updRows);
        if (!parsedUpdate.success) {
          return [new Error(`update_failed: ${parsedUpdate.error.message}`), null];
        }

        const updRow = parsedUpdate.data[0];
        if (updRow === undefined) {
          return [new Error('Failed to update booking status'), null];
        }

        const updatedBooking: UpdatedBooking = {
          booking_id: updRow[0],
          status: updRow[1],
          cancelled_by: updRow[2],
          cancellation_reason: updRow[3],
        };

        await tx.unsafe(
          `INSERT INTO booking_audit (booking_id, from_status, to_status, changed_by, actor_id, reason, metadata)
           VALUES ($1::uuid, $2, 'cancelled', $3, $4::uuid, $5, $6::jsonb)`,
          [
            input.booking_id,
            booking.status,
            input.actor,
            input.actor_id ?? null,
            input.reason ?? 'Cancelled via API',
            JSON.stringify({
              gcal_provider_event_id: booking.gcal_provider_event_id,
              gcal_client_event_id: booking.gcal_client_event_id,
            }),
          ],
        );

        return [null, updatedBooking];
      },
    );

    if (txErr !== null || updated === null) {
      return [txErr ?? new Error('Unknown transaction error'), null];
    }

    // 5. Mark GCal events for cleanup
    if (booking.gcal_provider_event_id !== null || booking.gcal_client_event_id !== null) {
      await sql`
        UPDATE bookings
        SET gcal_sync_status = 'pending', gcal_retry_count = 0
        WHERE booking_id = ${input.booking_id}::uuid
      `;
    }

    const result: CancelResult = {
      booking_id: toUUID(updated.booking_id),
      previous_status: booking.status,
      new_status: updated.status,
      cancelled_by: updated.cancelled_by,
      cancellation_reason: updated.cancellation_reason,
    };

    return [null, result];
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    return [new Error(`Internal error: ${message}`), null];
  } finally {
    await sql.end();
  }
}

