async function getBookingsForWindow(
  tx: postgres.TransactionSql,
  window: ReminderWindow,
  start: Date,
  end: Date
): Promise<BookingRecord[]> {
  if (window === '24h') return await getBookingsFor24h(tx, start, end);
  if (window === '2h') return await getBookingsFor2h(tx, start, end);
  return await getBookingsFor30min(tx, start, end);
}

interface CronResult {
  readonly reminders_24h_sent: number;
  readonly reminders_2h_sent: number;
  readonly reminders_30min_sent: number;
  readonly errors: number;
  readonly dry_run: boolean;
  readonly processed_bookings: string[];
}

export async function main(rawInput: unknown): Promise<[Error | null, CronResult | null]> {
  try {
    const parsed = InputSchema.safeParse(rawInput);
    if (!parsed.success) {
      return [new Error(`Invalid input: ${parsed.error.message}`), null];
    }

    const { dry_run, timezone } = parsed.data;

    const dbUrl = process.env['DATABASE_URL'];
    if (!dbUrl) {
      return [new Error('DATABASE_URL not configured'), null];
    }

    const sql = createDbClient({ url: dbUrl });

    const now = new Date();
    const window24hStart = new Date(now.getTime() + 23 * 60 * 60 * 1000);
    const window24hEnd = new Date(now.getTime() + 25 * 60 * 60 * 1000);
    const window2hStart = new Date(now.getTime() + 110 * 60 * 1000);
    const window2hEnd = new Date(now.getTime() + 130 * 60 * 1000);
    const window30minStart = new Date(now.getTime() + 25 * 60 * 1000);
    const window30minEnd = new Date(now.getTime() + 35 * 60 * 1000);

    const result = {
      reminders_24h_sent: 0,
      reminders_2h_sent: 0,
      reminders_30min_sent: 0,
      errors: 0,
      dry_run,
      processed_bookings: [],
    };

    // First, fetch all providers using the fallback bypass ID
    const [providersErr, providers] = await withTenantContext<{ provider_id: string }[]>(
      sql,
      NULL_TENANT_UUID,
      async (tx) => {
        const rows = await tx<{ provider_id: string }[]>`SELECT provider_id FROM providers`;
        return [null, rows];
      }
    );

    if (providersErr || !providers) {
      await sql.end();
      return [new Error(`Failed to fetch providers: ${providersErr?.message ?? 'Unknown'}`), null];
    }

    const processWindow = async (
      tenantId: string,
      window: ReminderWindow,
      start: Date,
      end: Date,
    ): Promise<void> => {
      const [err, bookings] = await withTenantContext<BookingRecord[]>(
        sql,
        tenantId,
        async (tx) => {
          const b = await getBookingsForWindow(tx, window, start, end);
          return [null, b];
        }
      );

      if (err || !bookings) {
        return; // Skip this window for this provider if error
      }

      for (const booking of bookings) {
        result.processed_bookings.push(booking.booking_id);
        const details = buildBookingDetails(booking, timezone);
        const prefs = booking.reminder_preferences;
        const buttons = buildInlineButtons(booking.booking_id, window);

        if (dry_run) {
          result[window === '24h' ? 'reminders_24h_sent' : window === '2h' ? 'reminders_2h_sent' : 'reminders_30min_sent']++;
          continue;
        }

        const messageType = `reminder_${window}`;

        if (booking.client_telegram_chat_id && getClientPreference(prefs, 'telegram', window)) {
          const tgResult = await sendTelegramReminder(
            booking.client_telegram_chat_id,
            messageType,
            details,
            buttons
          );
          if (!tgResult.sent) {
            result.errors++;
          }
        }

        if (booking.client_email && getClientPreference(prefs, 'gmail', window)) {
          const gmResult = await sendGmailReminder(
            booking.client_email,
            messageType,
            details,
            booking.booking_id
          );
          if (!gmResult.sent) {
            result.errors++;
          }
        }

        const [updateErr] = await withTenantContext<boolean>(
          sql,
          tenantId,
          async (tx) => {
            await markReminderSent(tx, booking.booking_id, window);
            return [null, true];
          }
        );

        if (updateErr) {
          result.errors++;
        } else {
          if (window === '24h') result.reminders_24h_sent++;
          else if (window === '2h') result.reminders_2h_sent++;
          else result.reminders_30min_sent++;
        }
      }
    };

    // Iterate through all providers and process each window
    for (const provider of providers) {
      const tenantId = provider.provider_id;
      await processWindow(tenantId, '24h', window24hStart, window24hEnd);
      await processWindow(tenantId, '2h', window2hStart, window2hEnd);
      await processWindow(tenantId, '30min', window30minStart, window30minEnd);
    }

    await sql.end();

    return [null, result];
  } catch (e) {
    const error = e instanceof Error ? e : new Error(String(e));
    return [new Error(error.message), null];
  }
}

import { NULL_TENANT_UUID, DEFAULT_TIMEZONE } from '../internal/config';
// ============================================================================
// TELEGRAM AUTO REGISTER — Auto-register user from Telegram payload
// ============================================================================
// Creates a user record from Telegram webhook payload.
// No password required — authentication is implicit via chat_id.
// Idempotent: returns existing user if chat_id already registered.
// ============================================================================

import { z } from 'zod';
import postgres from 'postgres';
import crypto from 'crypto';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

/*
 * PRE-FLIGHT CHECKLIST
 * Mission         : Telegram bot send/callback/gateway/menu operation
 * DB Tables Used  : clients, providers, bookings (varies by action)
 * Concurrency Risk: NO — Telegram API is stateless per message
 * GCal Calls      : NO
 * Idempotency Key : NO — Telegram message ID used for deduplication
 * RLS Tenant ID   : YES — withTenantContext wraps all queries
 * Zod Schemas     : YES — InputSchema validates all inputs
 *
 * ## REASONING TRACE
 * ### Mission Decomposition
 * - Validate input → Route action → Execute → Format response → Return
 * ### Schema Verification
 * - All tables/columns verified against AGENTS.md §6 + migrations
 * ### Failure Mode Analysis
 * - Telegram API failures → error returned to caller
 * - DB failures → transaction rollback → error returned
 * ### Concurrency Analysis
 * - Risk: LOW — Telegram messages processed sequentially per chat
 * ### SOLID Compliance Check
 * - SRP: YES — DRY: YES — KISS: YES
 * → CLEARED FOR CODE GENERATION
 */
const InputSchema = z.object({
  chat_id: z.string().min(1),
  first_name: z.string().min(1).max(200),
  last_name: z.string().max(200).optional(),
});

interface TelegramUserResult {
  readonly user_id: string;
  readonly full_name: string;
  readonly telegram_chat_id: string;
  readonly role: string;
  readonly is_new: boolean;
  readonly profile_complete: boolean;
}

function hashPasswordSync(password: string): string {
  const salt = crypto.randomBytes(16).toString('hex');
  const key = crypto.scryptSync(password, salt, 64);
  return `${salt}:${key.toString('hex')}`;
}

export async function main(rawInput: unknown): Promise<[Error | null, TelegramUserResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error('Validation error: ' + parsed.error.message), null];
  }

  const { chat_id, first_name, last_name } = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is not set'), null];
  }

  const fullName = last_name !== undefined && last_name !== ''
    ? `${first_name} ${last_name}`
    : first_name;

  const sql = createDbClient({ url: dbUrl });

  // No specific UUID provided in payload for tenant context
  const tenantId = NULL_TENANT_UUID;

  try {
    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
      const existingRows = await tx`
        SELECT user_id, full_name, telegram_chat_id, role,
               CASE WHEN rut IS NOT NULL AND email IS NOT NULL AND password_hash IS NOT NULL
                    THEN true ELSE false END AS profile_complete
        FROM users
        WHERE telegram_chat_id = ${chat_id}
        LIMIT 1
      `;

      const existingRow = existingRows[0];
      if (existingRow !== undefined) {
        return [null, {
          user_id: String(existingRow.user_id),
          full_name: String(existingRow.full_name),
          telegram_chat_id: String(existingRow.telegram_chat_id),
          role: String(existingRow.role),
          is_new: false,
          profile_complete: Boolean(existingRow.profile_complete),
        }];
      }

      const tempPassword = crypto.randomBytes(32).toString('hex');
      const passwordHash = hashPasswordSync(tempPassword);

      const insertRows = await tx`
        INSERT INTO users (
          full_name, telegram_chat_id, role, password_hash,
          is_active, timezone
        ) VALUES (
          ${fullName}, ${chat_id}, 'client', ${passwordHash},
          true, DEFAULT_TIMEZONE
        )
        RETURNING user_id, full_name, telegram_chat_id, role
      `;

      const newRow = insertRows[0];
      if (newRow === undefined) {
        return [new Error('Failed to create user record'), null];
      }

      return [null, {
        user_id: String(newRow.user_id),
        full_name: String(newRow.full_name),
        telegram_chat_id: String(newRow.telegram_chat_id),
        role: String(newRow.role),
        is_new: true,
        profile_complete: false,
      }];
    });

    if (txErr) {
      return [txErr, null];
    }

    return [null, txData];
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    return [new Error('Internal error: ' + message), null];
  } finally {
    await sql.end();
  }
}

