// ============================================================================
// INPUT SCHEMA — Telegram webhook payload
// When called via Windmill webhook, the body arrives as a JSON string
// that we need to parse first.
// ============================================================================

/*
 * PRE-FLIGHT CHECKLIST
 * Mission         : Telegram bot send/callback/gateway/menu operation
 * DB Tables Used  : clients, providers, bookings (varies by action)
 * Concurrency Risk: NO — Telegram API is stateless per message
 * GCal Calls      : NO
 * Idempotency Key : NO — Telegram message ID used for deduplication
 * RLS Tenant ID   : YES — withTenantContext wraps all queries
 * Zod Schemas     : YES — InputSchema validates all inputs
 *
 * ## REASONING TRACE
 * ### Mission Decomposition
 * - Validate input → Route action → Execute → Format response → Return
 * ### Schema Verification
 * - All tables/columns verified against AGENTS.md §6 + migrations
 * ### Failure Mode Analysis
 * - Telegram API failures → error returned to caller
 * - DB failures → transaction rollback → error returned
 * ### Concurrency Analysis
 * - Risk: LOW — Telegram messages processed sequentially per chat
 * ### SOLID Compliance Check
 * - SRP: YES — DRY: YES — KISS: YES
 * → CLEARED FOR CODE GENERATION
 */
const RawBodySchema = z.object({
  update_id: z.number().optional(),
  message: z.object({
    message_id: z.number().optional(),
    from: z.object({
      id: z.number().optional(),
      is_bot: z.boolean().optional(),
      first_name: z.string().optional().default('Usuario'),
      last_name: z.string().optional(),
      username: z.string().optional(),
    }).optional(),
    chat: z.object({
      id: z.number(),
      type: z.enum(['private', 'group', 'supergroup', 'channel']).optional(),
      first_name: z.string().optional(),
      last_name: z.string().optional(),
      username: z.string().optional(),
    }),
    date: z.number().optional(),
    text: z.string().optional(),
  }).optional(),
  callback_query: z.object({
    id: z.string(),
    from: z.object({ id: z.number() }),
    message: z.unknown().optional(),
    data: z.string(),
  }).optional(),
});

// ============================================================================
// RESPONSE HELPERS
// ============================================================================

const BOT_TOKEN = process.env['TELEGRAM_BOT_TOKEN'] ?? '';
const CHAT_ID = process.env['TELEGRAM_ID'] ?? '';

async function sendTelegramMessage(chatId: string, text: string, options?: { parse_mode?: string; reply_markup?: Record<string, unknown> }): Promise<[Error | null, unknown]> {
  try {
    const url = `https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`;
    const body: Record<string, unknown> = {
      chat_id: chatId,
      text,
      parse_mode: options?.parse_mode ?? 'Markdown',
    };
    if (options?.reply_markup != null) body.reply_markup = options.reply_markup;

    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });

    if (!response.ok) {
      const errorText = await response.text();
      return [new Error(`Telegram API error: ${response.status} ${errorText}`), null];
    }

    const data = await response.json();
    return [null, data];
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return [new Error(`send_message_failed: ${msg}`), null];
  }
}

