interface RegionRow {
  readonly region_id: number;
  readonly name: string;
  readonly code: string;
  readonly country_code: string;
  readonly is_active: boolean;
  readonly sort_order: number;
}

interface CommuneRow {
  readonly commune_id: number;
  readonly name: string;
  readonly region_id: number;
  readonly is_active: boolean;
  readonly region_name: string;
}

function mapRegionRow(row: [number, string, string, string, boolean, number]): RegionRow {
  return Object.freeze({
    region_id: row[0], name: row[1], code: row[2],
    country_code: row[3], is_active: row[4], sort_order: row[5],
  });
}

function mapCommuneRow(row: [number, string, number, boolean, string]): CommuneRow {
  return Object.freeze({
    commune_id: row[0], name: row[1], region_id: row[2],
    is_active: row[3], region_name: row[4],
  });
}

type Result<T> = [Error | null, T | null];

async function handleListRegions(
  tx: postgres.TransactionSql,
): Promise<Result<{ readonly regions: readonly RegionRow[]; readonly count: number }>> {
  const rows = await tx.values<[number, string, string, string, boolean, number][]>`
    SELECT region_id, name, code, country_code, is_active, sort_order
    FROM regions WHERE is_active = true ORDER BY sort_order ASC, name ASC
  `;
  const regions = rows.map(mapRegionRow);
  return [null, { regions, count: regions.length }];
}

async function handleListCommunes(
  tx: postgres.TransactionSql,
  regionId: number | undefined,
): Promise<Result<{ readonly communes: readonly CommuneRow[]; readonly count: number }>> {
  let rows: [number, string, number, boolean, string][];
  if (regionId != null) {
    rows = await tx.values<[number, string, number, boolean, string][]>`
      SELECT c.commune_id, c.name, c.region_id, c.is_active, r.name AS region_name
      FROM communes c JOIN regions r ON r.region_id = c.region_id
      WHERE c.is_active = true AND c.region_id = ${regionId}
      ORDER BY c.name ASC
    `;
  } else {
    rows = await tx.values<[number, string, number, boolean, string][]>`
      SELECT c.commune_id, c.name, c.region_id, c.is_active, r.name AS region_name
      FROM communes c JOIN regions r ON r.region_id = c.region_id
      WHERE c.is_active = true ORDER BY r.sort_order ASC, c.name ASC
    `;
  }
  const communes = rows.map(mapCommuneRow);
  return [null, { communes, count: communes.length }];
}

async function handleSearchCommunes(
  tx: postgres.TransactionSql,
  regionId: number | undefined,
  search: string,
): Promise<Result<{ readonly communes: readonly CommuneRow[]; readonly count: number }>> {
  let rows: [number, string, number, boolean, string][];
  if (regionId != null) {
    rows = await tx.values<[number, string, number, boolean, string][]>`
      SELECT c.commune_id, c.name, c.region_id, c.is_active, r.name AS region_name
      FROM communes c JOIN regions r ON r.region_id = c.region_id
      WHERE c.is_active = true AND c.region_id = ${regionId}
        AND LOWER(c.name) LIKE LOWER(${`%${search}%`})
      ORDER BY c.name ASC LIMIT ${LIMIT_50}
    `;
  } else {
    rows = await tx.values<[number, string, number, boolean, string][]>`
      SELECT c.commune_id, c.name, c.region_id, c.is_active, r.name AS region_name
      FROM communes c JOIN regions r ON r.region_id = c.region_id
      WHERE c.is_active = true AND LOWER(c.name) LIKE LOWER(${`%${search}%`})
      ORDER BY r.sort_order ASC, c.name ASC LIMIT ${LIMIT_50}
    `;
  }
  const communes = rows.map(mapCommuneRow);
  return [null, { communes, count: communes.length }];
}

