    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is required'), null];
  }

  // Reference data — use a fixed admin tenant ID
  const tenantId = NULL_TENANT_UUID;
  const sql = createDbClient({ url: dbUrl });

  const [err, result] = await withTenantContext(sql, tenantId, async (tx) => {
    switch (input.action) {
      case 'list_regions': return handleListRegions(tx);
      case 'list_communes': return handleListCommunes(tx, input.region_id);
      case 'search_communes': return handleSearchCommunes(tx, input.region_id, input.search ?? '');
    }
  });

  await sql.end().catch(() => { /* swallow */ });
  return [err, result];
}

