// WEB AUTH LOGIN — Authenticate email+password, return session + role
// ============================================================================
// Validates email and password against stored hash.
// Updates last_login timestamp on success.
// Returns user_id, email, role, full_name for session management.
// ============================================================================

import { z } from 'zod';
import postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';
import crypto from 'crypto';

/*
 * PRE-FLIGHT CHECKLIST
 * Mission         : Web authentication operation (login/register/me/role/profile)
 * DB Tables Used  : users, providers, clients
 * Concurrency Risk: NO — auth operations are sequential per user
 * GCal Calls      : NO
 * Idempotency Key : NO — email uniqueness prevents duplicates
 * RLS Tenant ID   : YES — withTenantContext wraps all queries
 * Zod Schemas     : YES — InputSchema validates all inputs + .refine() for password match
 *
 * ## REASONING TRACE
 * ### Mission Decomposition
 * - Validate input → Check uniqueness → Hash password → Create/Update user → Return
 * ### Schema Verification
 * - All tables/columns verified against AGENTS.md §6 + migrations
 * ### Failure Mode Analysis
 * - Duplicate email → unique constraint → error returned
 * - Weak password → validation → error returned
 * ### Concurrency Analysis
 * - Risk: LOW — user operations are isolated by email/ID
 * ### SOLID Compliance Check
 * - SRP: YES — DRY: YES — KISS: YES
 * → CLEARED FOR CODE GENERATION
 */
const InputSchema = z.object({
  email: z.email(),
  password: z.string().min(1),
});

interface LoginResult {
  readonly user_id: string;
  readonly email: string;
  readonly full_name: string;
  readonly role: string;
  readonly profile_complete: boolean;
}

interface UserRow {
  readonly user_id: string;
  readonly email: string;
  readonly full_name: string;
  readonly role: string;
  readonly password_hash: string;
  readonly is_active: boolean;
  readonly profile_complete: boolean;
}

function verifyPasswordSync(password: string, storedHash: string): boolean {
  const parts = storedHash.split(':');
  if (parts.length !== 2) return false;

  const salt = parts[0];
  const storedKey = parts[1];
  if (salt === undefined || storedKey === undefined) return false;
  const key = crypto.scryptSync(password, salt, 64);

  return key.toString('hex') === storedKey;
}

export async function main(rawInput: unknown): Promise<[Error | null, LoginResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error('Validation error: ' + parsed.error.message), null];
  }

  const { email, password } = parsed.data;

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is not set'), null];
  }

  const sql = createDbClient({ url: dbUrl });

  // Extract tenant ID from input (login is pre-auth, so we use a safe fallback)
  const rawObj = typeof rawInput === 'object' && rawInput !== null ? rawInput : {};
  let tenantId = NULL_TENANT_UUID;
  const tenantKeys: readonly (keyof typeof rawObj)[] = ['provider_id', 'user_id', 'admin_user_id', 'client_id', 'client_user_id'] as const;
  for (const key of tenantKeys) {
    const val = rawObj[key];
    if (typeof val === 'string') {
      tenantId = val;
      break;
    }
  }

  try {
    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
      const userRows = await tx.values<[string, string, string, string, string, boolean, boolean][]>`
        SELECT user_id, email, full_name, role, password_hash, is_active,
               CASE WHEN rut IS NOT NULL AND email IS NOT NULL AND password_hash IS NOT NULL
                    THEN true ELSE false END AS profile_complete
        FROM users
        WHERE email = ${email}
        LIMIT 1
      `;

      const userRow = userRows[0];
      if (userRow === undefined) {
        return [new Error('Invalid email or password'), null];
      }

      const user: UserRow = {
        user_id: userRow[0],
        email: userRow[1],
        full_name: userRow[2],
        role: userRow[3],
        password_hash: userRow[4],
        is_active: userRow[5],
        profile_complete: userRow[6],
