// WEB AUTH REGISTER — Register new user via web (hash password)
// ============================================================================
// Registers a new user with full profile data.
// Validates Chilean RUT (módulo 11), email uniqueness, password strength.
// Default role: 'client'.
// ============================================================================

import { z } from 'zod';
import postgres from 'postgres';
import crypto from 'crypto';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

/*
 * PRE-FLIGHT CHECKLIST
 * Mission         : Web authentication operation (login/register/me/role/profile)
 * DB Tables Used  : users, providers, clients
 * Concurrency Risk: NO — auth operations are sequential per user
 * GCal Calls      : NO
 * Idempotency Key : NO — email uniqueness prevents duplicates
 * RLS Tenant ID   : YES — withTenantContext wraps all queries
 * Zod Schemas     : YES — InputSchema validates all inputs + .refine() for password match
 *
 * ## REASONING TRACE
 * ### Mission Decomposition
 * - Validate input → Check uniqueness → Hash password → Create/Update user → Return
 * ### Schema Verification
 * - All tables/columns verified against AGENTS.md §6 + migrations
 * ### Failure Mode Analysis
 * - Duplicate email → unique constraint → error returned
 * - Weak password → validation → error returned
 * ### Concurrency Analysis
 * - Risk: LOW — user operations are isolated by email/ID
 * ### SOLID Compliance Check
 * - SRP: YES — DRY: YES — KISS: YES
 * → CLEARED FOR CODE GENERATION
 */
const InputSchema = z.object({
  full_name: z.string().min(3).max(200),
  rut: z.string().min(1).max(12),
  email: z.email(),
  address: z.string().min(1).max(300),
  phone: z.string().min(1).max(50),
  password: z.string().min(8).max(128),
  password_confirm: z.string().min(8).max(128),
  timezone: z.string().default(DEFAULT_TIMEZONE),
}).refine(d => d.password === d.password_confirm, {
  message: 'Passwords do not match',
  path: ['password_confirm'],
});

interface RegisterResult {
  readonly user_id: string;
  readonly email: string;
  readonly full_name: string;
  readonly role: string;
}

function validateRut(rut: string): boolean {
  const clean = rut.replace(/[.]/g, '').replace(/-/g, '').toUpperCase();
  if (clean.length < 2) return false;

  const body = clean.slice(0, -1);
  const dv = clean.slice(-1);

  if (!/^\d+$/.test(body)) return false;
  if (!/^[\dK]$/.test(dv)) return false;

  let sum = 0;
  let multiplier = 2;

  for (let i = body.length - 1; i >= 0; i--) {
    const digit = body[i];
    if (digit === undefined) continue;
    sum += Number.parseInt(digit) * multiplier;
    multiplier = multiplier === 7 ? 2 : multiplier + 1;
  }

  const remainder = 11 - (sum % 11);
  const expectedDv = remainder === 11 ? '0' : remainder === 10 ? 'K' : String(remainder);

  return dv === expectedDv;
}

function validatePasswordStrength(password: string): string | null {
  if (password.length < 8) return 'Password must be at least 8 characters';
  if (!/[A-Z]/.test(password)) return 'Password must contain at least one uppercase letter';
  if (!/[0-9]/.test(password)) return 'Password must contain at least one number';
  if (!/[^A-Za-z0-9]/.test(password)) return 'Password must contain at least one special character';
  return null;
}

function hashPasswordSync(password: string): string {
  const salt = crypto.randomBytes(16).toString('hex');
  const key = crypto.scryptSync(password, salt, 64);
  return `${salt}:${key.toString('hex')}`;
}

export async function main(rawInput: unknown): Promise<[Error | null, RegisterResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) {
    return [new Error('Validation error: ' + parsed.error.message), null];
  }

  const { full_name, rut, email, address, phone, password, timezone } = parsed.data;

  // Password match validated by Zod .refine() — only strength check remains
  const passwordError = validatePasswordStrength(password);
  if (passwordError !== null) {
    return [new Error(passwordError), null];
  }

  if (!validateRut(rut)) {
    return [new Error('Invalid Chilean RUT format or verification digit'), null];
  }

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') {
    return [new Error('CONFIGURATION_ERROR: DATABASE_URL is not set'), null];
  }

  const passwordHash = hashPasswordSync(password);
  const sql = createDbClient({ url: dbUrl });
  const tenantId = NULL_TENANT_UUID; // No user_id yet

  try {
    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
      const existingRows = await tx`
        SELECT user_id FROM users WHERE email = ${email} OR rut = ${rut} LIMIT 1
      `;

      const existingRow = existingRows[0];
      if (existingRow !== undefined) {
        return [new Error('A user with this email or RUT already exists'), null];
      }

      const insertRows = await tx`
        INSERT INTO users (
          full_name, rut, email, address, phone, password_hash,
          role, is_active, timezone
        ) VALUES (
          ${full_name}, ${rut}, ${email}, ${address}, ${phone}, ${passwordHash},
          'client', true, ${timezone}
        )
        RETURNING user_id, email, full_name, role
      `;

      const newRow = insertRows[0];
      if (newRow === undefined) {
        return [new Error('Failed to create user record'), null];
      }

      return [null, {
        user_id: String(newRow.user_id),
        email: String(newRow.email),
        full_name: String(newRow.full_name),
        role: String(newRow.role),
      }];
    });

    if (txErr) return [txErr, null];
    return [null, txData];
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    if (message.includes('duplicate key') || message.includes('unique constraint')) {
      return [new Error('A user with this email or RUT already exists'), null];
    }
    return [new Error('Internal error: ' + message), null];
  } finally {
    await sql.end();
  }
}

