// ============================================================================
// WEB WAITLIST — Waitlist CRUD (join, leave, list, position)
// ============================================================================
// Manages client waitlist entries for services.
// Actions: join, leave, list, check_position
// SRP: Each action extracted into its own handler function.
// ============================================================================

import { z } from 'zod';
import postgres from 'postgres';
import { withTenantContext } from '../internal/tenant-context';
import { createDbClient } from '../internal/db/client';

/*
 * PRE-FLIGHT CHECKLIST
 * Mission         : Waitlist CRUD operations (join/leave/list/check_position)
 * DB Tables Used  : waitlist, users, clients, services
 * Concurrency Risk: YES — position calculation requires transactional integrity
 * GCal Calls      : NO
 * Idempotency Key : NO — duplicate join check prevents double-entry
 * RLS Tenant ID   : YES — withTenantContext wraps all queries
 * Zod Schemas     : YES — InputSchema validates all inputs
 *
 * ## REASONING TRACE
 * ### Mission Decomposition
 * - Validate input → Resolve client → Route action → Execute handler → Return
 * ### Schema Verification
 * - waitlist (waitlist_id, client_id, service_id, status, position, ...)
 * - users, clients, services — standard relationships
 * ### Failure Mode Analysis
 * - DB failures → transaction rollback → error returned
 * - Duplicate join → checked before insert → error returned
 * ### Concurrency Analysis
 * - Risk: YES — simultaneous joins could compute same position
 * - Lock strategy: transaction isolation + COUNT(*) inside tx
 * ### SOLID Compliance Check
 * - SRP: YES — each handler does one thing
 * - DRY: YES — shared resolveClient helper
 * - KISS: YES — straightforward CRUD
 *
 * → CLEARED FOR CODE GENERATION
 */

type Result<T> = [Error | null, T | null];

interface WaitlistEntry {
  readonly waitlist_id: string;
  readonly service_id: string;
  readonly preferred_date: string | null;
  readonly preferred_start_time: string | null;
  readonly status: string;
  readonly position: number;
  readonly created_at: string;
}

interface WaitlistResult {
  readonly entries: readonly WaitlistEntry[];
  readonly position: number | null;
  readonly message: string;
}

const InputSchema = z.object({
  action: z.enum(['join', 'leave', 'list', 'check_position']),
  user_id: z.uuid(),
  client_id: z.uuid().optional(),
  service_id: z.uuid().optional(),
  waitlist_id: z.uuid().optional(),
  preferred_date: z.string().optional(),
  preferred_start_time: z.string().optional(),
  preferred_end_time: z.string().optional(),
});

// ─── Shared: Resolve client from user ───────────────────────────────────────

interface ClientInfo {
  readonly clientId: string;
}

async function resolveClient(
  tx: postgres.TransactionSql,
  userId: string,
  providedClientId: string | undefined,
): Promise<Result<ClientInfo>> {
  const userRows = await tx`
    SELECT u.user_id, p.client_id FROM users u
    LEFT JOIN clients p ON p.client_id = u.user_id OR p.email = u.email
    WHERE u.user_id = ${userId}::uuid LIMIT 1
  `;
  const userRow = userRows[0];
  if (userRow === undefined) return [new Error('User not found'), null];

  const clientId = userRow.client_id !== null ? String(userRow.client_id) : (providedClientId ?? null);
  if (clientId === null) return [new Error('Client record not found'), null];

  return [null, { clientId }];
}

// ─── Action Handlers ────────────────────────────────────────────────────────

async function handleJoin(
  tx: postgres.TransactionSql,
  clientId: string,
  input: Readonly<z.infer<typeof InputSchema>>,
): Promise<Result<WaitlistResult>> {
  const serviceId = input.service_id;
  if (serviceId === undefined) return [new Error('service_id is required for join'), null];

  const existingRows = await tx`
    SELECT waitlist_id FROM waitlist
    WHERE client_id = ${clientId}::uuid AND service_id = ${serviceId}::uuid
      AND status IN ('waiting', 'notified')
    LIMIT 1
  `;
  if (existingRows[0] !== undefined) return [new Error('Already on waitlist for this service'), null];

  const countRows = await tx`
    SELECT COUNT(*) AS cnt FROM waitlist
    WHERE service_id = ${serviceId}::uuid AND status = 'waiting'
  `;
  const position = countRows[0] !== undefined ? Number(countRows[0].cnt) + 1 : 1;

  const insertRows = await tx`
    INSERT INTO waitlist (
      client_id, service_id, preferred_date,
      preferred_start_time, preferred_end_time, status, position
    ) VALUES (
      ${clientId}::uuid, ${serviceId}::uuid,
      ${input.preferred_date ?? null},
      ${input.preferred_start_time ?? null},
      ${input.preferred_end_time ?? null},
      'waiting', ${position}
    )
    RETURNING waitlist_id
  `;
  if (insertRows[0] === undefined) return [new Error('Failed to join waitlist'), null];

  return [null, { entries: [], position, message: 'Joined waitlist at position ' + String(position) }];
}

async function handleLeave(
  tx: postgres.TransactionSql,
  clientId: string,
  input: Readonly<z.infer<typeof InputSchema>>,
): Promise<Result<WaitlistResult>> {
  const waitlistId = input.waitlist_id;
  if (waitlistId === undefined) return [new Error('waitlist_id is required for leave'), null];

  await tx`
    UPDATE waitlist SET status = 'cancelled', updated_at = NOW()
    WHERE waitlist_id = ${waitlistId}::uuid AND client_id = ${clientId}::uuid
      AND status IN ('waiting', 'notified')
  `;

  await tx.unsafe(
    "SELECT recalculate_waitlist_positions(service_id) FROM waitlist WHERE waitlist_id = $1::uuid",
    [waitlistId]
  );

  return [null, { entries: [], position: null, message: 'Left waitlist successfully' }];
}

async function handleList(
  tx: postgres.TransactionSql,
  clientId: string,
): Promise<Result<WaitlistResult>> {
  const rows = await tx`
    SELECT waitlist_id, service_id, preferred_date,
           preferred_start_time, status, position, created_at
    FROM waitlist
    WHERE client_id = ${clientId}::uuid AND status IN ('waiting', 'notified')
    ORDER BY created_at DESC
  `;

  const entries: WaitlistEntry[] = [];
  for (const r of rows) {
    entries.push({
      waitlist_id: String(r.waitlist_id),
      service_id: String(r.service_id),
      preferred_date: r.preferred_date !== null ? String(r.preferred_date) : null,
      preferred_start_time: r.preferred_start_time !== null ? String(r.preferred_start_time) : null,
      status: String(r.status),
      position: Number(r.position),
      created_at: String(r.created_at),
    });
  }

  return [null, { entries, position: null, message: 'OK' }];
}

async function handleCheckPosition(
  tx: postgres.TransactionSql,
  clientId: string,
  input: Readonly<z.infer<typeof InputSchema>>,
): Promise<Result<WaitlistResult>> {
  const waitlistId = input.waitlist_id;
  if (waitlistId === undefined) return [new Error('waitlist_id is required for check_position'), null];

  const rows = await tx`
    SELECT position, status FROM waitlist
    WHERE waitlist_id = ${waitlistId}::uuid AND client_id = ${clientId}::uuid
    LIMIT 1
  `;
  const row = rows[0];
  if (row === undefined) return [new Error('Waitlist entry not found'), null];

  return [null, { entries: [], position: Number(row.position), message: 'Your position: ' + String(row.position) }];
}

// ─── Main Entry Point (pure router — <40 lines) ────────────────────────────

export async function main(rawInput: unknown): Promise<[Error | null, WaitlistResult | null]> {
  const parsed = InputSchema.safeParse(rawInput);
  if (!parsed.success) return [new Error('Validation error: ' + parsed.error.message), null];

  const dbUrl = process.env['DATABASE_URL'];
  if (dbUrl === undefined || dbUrl === '') return [new Error('CONFIGURATION_ERROR: DATABASE_URL is not set'), null];

  const sql = createDbClient({ url: dbUrl });
  const tenantId = parsed.data.client_id ?? parsed.data.user_id ?? NULL_TENANT_UUID;

  try {
    const [txErr, txData] = await withTenantContext(sql, tenantId, async (tx) => {
      const [clientErr, client] = await resolveClient(tx, parsed.data.user_id, parsed.data.client_id);
      if (clientErr !== null || client === null) return [clientErr ?? new Error('Client not found'), null];

      switch (parsed.data.action) {
        case 'join': return handleJoin(tx, client.clientId, parsed.data);
        case 'leave': return handleLeave(tx, client.clientId, parsed.data);
        case 'list': return handleList(tx, client.clientId);
        case 'check_position': return handleCheckPosition(tx, client.clientId, parsed.data);
      }
    });

    await sql.end().catch(() => { /* swallow */ });
    return txErr !== null ? [txErr, null] : [null, txData];
  } catch (e) {
    await sql.end().catch(() => { /* swallow */ });
    const message = e instanceof Error ? e.message : String(e);
    return [new Error('Internal error: ' + message), null];
  }
}

