      process.env[key] = value;
    }
    console.log(`[global-setup] Loaded ${Object.keys(envVars).length} env vars from ${envPath}`);
  } catch (e) {
    console.warn(`[global-setup] Could not load ${envPath}:`, e);
  }
}
